import{_ as t,c as s,o as i,a1 as a}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Context Compaction: Auto-Restore Skills | opencode-agent-skills","description":"Learn how context compaction resilience works in opencode-agent-skills plugins. Understand auto-restoration triggers, verify effects, master troubleshooting methods, ensure skills remain available in long sessions, and improve the skill usage experience.","frontmatter":{"title":"Context Compaction: Auto-Restore Skills | opencode-agent-skills","sidebarTitle":"Context Compaction","subtitle":"Context Compaction: Auto-Restore Skills","description":"Learn how context compaction resilience works in opencode-agent-skills plugins. Understand auto-restoration triggers, verify effects, master troubleshooting methods, ensure skills remain available in long sessions, and improve the skill usage experience.","tags":["Context Management","Session Persistence","Advanced Feature"],"prerequisite":["/joshuadavidthomas/opencode-agent-skills/platforms-loading-skills-into-context"],"order":4},"headers":[],"relativePath":"joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md","filePath":"joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"}'),o={name:"joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"};function n(l,e,r,c,d,p){return i(),s("div",null,[...e[0]||(e[0]=[a(`<h1 id="context-compaction-resilience" tabindex="-1">Context Compaction Resilience <a class="header-anchor" href="#context-compaction-resilience" aria-label="Permalink to &quot;Context Compaction Resilience&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Understand how plugins keep skills available after session compaction</li><li>Know when compaction restoration triggers and its execution flow</li><li>Be able to verify that compaction restoration works correctly</li><li>Understand the role of synthetic messages in the restoration mechanism</li></ul><h2 id="your-current-struggle" tabindex="-1">Your Current Struggle <a class="header-anchor" href="#your-current-struggle" aria-label="Permalink to &quot;Your Current Struggle&quot;">​</a></h2><p>In long sessions, OpenCode performs <strong>context compaction</strong> to save tokens. The compacted session retains only recent messages, and early history (including previously injected skill content) is removed.</p><p>This creates a problem: if skill content is compacted away, the AI no longer knows which skills are available and cannot use loaded skills.</p><h2 id="when-to-use-this" tabindex="-1">When to Use This <a class="header-anchor" href="#when-to-use-this" aria-label="Permalink to &quot;When to Use This&quot;">​</a></h2><p>The compaction restoration mechanism runs <strong>automatically</strong>—no manual intervention is needed. But understanding its principles helps you troubleshoot in these scenarios:</p><ul><li>AI suddenly &quot;forgets&quot; skills during a long session</li><li>Need to debug skill availability after compaction</li><li>Want to understand the plugin&#39;s session management strategy</li></ul><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><h3 id="what-is-context-compaction" tabindex="-1">What is Context Compaction? <a class="header-anchor" href="#what-is-context-compaction" aria-label="Permalink to &quot;What is Context Compaction?&quot;">​</a></h3><p>OpenCode sessions grow longer as messages accumulate. When token usage approaches the limit, the system automatically performs <strong>context compaction</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Session Start] → [Message 1] → [Message 2] → ... → [Message 50]</span></span>
<span class="line"><span>                          ↑ Compaction point: keep only last 10 messages</span></span></code></pre></div><p>After compaction, early messages (including skill injection content) are removed, and the AI only sees recent message history.</p><h3 id="how-compaction-restoration-works" tabindex="-1">How Compaction Restoration Works <a class="header-anchor" href="#how-compaction-restoration-works" aria-label="Permalink to &quot;How Compaction Restoration Works&quot;">​</a></h3><p>The plugin listens for the <code>session.compacted</code> event. Once compaction is detected, it immediately executes the following restoration steps:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Session compaction triggered] --&gt; B[session.compacted event]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C{Superpowers enabled?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|Yes| D[Re-inject Superpowers prompt]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|No| E[Skip Superpowers]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; F[Re-inject skill list]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[Clear loaded skills record]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[Restoration complete]</span></span></code></pre></div><p><strong>Key points</strong>:</p><ul><li>Restoration is <strong>automatic</strong>—no manual trigger required</li><li>The restored skill list includes <strong>all discovered skills</strong> (not just previously loaded ones)</li><li>The loaded skills record is cleared, allowing the AI to re-evaluate which skills it needs</li></ul><h3 id="the-role-of-synthetic-messages" tabindex="-1">The Role of Synthetic Messages <a class="header-anchor" href="#the-role-of-synthetic-messages" aria-label="Permalink to &quot;The Role of Synthetic Messages&quot;">​</a></h3><p>The plugin uses the <strong>Synthetic Message Injection</strong> mechanism to inject content:</p><table tabindex="0"><thead><tr><th>Property</th><th>Value</th><th>Meaning</th></tr></thead><tbody><tr><td><code>noReply</code></td><td><code>true</code></td><td>AI does not reply to the injected content itself</td></tr><tr><td><code>synthetic</code></td><td><code>true</code></td><td>Marked as system-generated content, not counted as user input, not shown in UI</td></tr></tbody></table><p>This means the content injected during compaction restoration:</p><ul><li>Is completely transparent to users (invisible)</li><li>Does not consume user message quota</li><li>But is read and understood by the AI</li></ul><h2 id="🎒-before-you-start" tabindex="-1">🎒 Before You Start <a class="header-anchor" href="#🎒-before-you-start" aria-label="Permalink to &quot;🎒 Before You Start&quot;">​</a></h2><p>This tutorial requires:</p><ul><li>OpenCode Agent Skills plugin installed</li><li>Understanding of skill loading basics</li><li>A long session for testing compaction effects</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>No special preparation needed—compaction restoration is a built-in plugin feature.</p></div><h2 id="follow-along-verify-compaction-restoration" tabindex="-1">Follow Along: Verify Compaction Restoration <a class="header-anchor" href="#follow-along-verify-compaction-restoration" aria-label="Permalink to &quot;Follow Along: Verify Compaction Restoration&quot;">​</a></h2><h3 id="step-1-start-a-new-session" tabindex="-1">Step 1: Start a New Session <a class="header-anchor" href="#step-1-start-a-new-session" aria-label="Permalink to &quot;Step 1: Start a New Session&quot;">​</a></h3><p><strong>Why</strong> Verify that the skill list is injected correctly during session initialization</p><p>Start a new session and enter any message:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Hello</span></span></code></pre></div><p><strong>You should see</strong>: AI responds normally, and the skill list is automatically injected in the background (invisible to users)</p><h3 id="step-2-load-a-skill" tabindex="-1">Step 2: Load a Skill <a class="header-anchor" href="#step-2-load-a-skill" aria-label="Permalink to &quot;Step 2: Load a Skill&quot;">​</a></h3><p><strong>Why</strong> Ensure skill content is injected into the context</p><p>Call the <code>use_skill</code> tool:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Use get_available_skills to view available skills, then use use_skill to load one of them</span></span></code></pre></div><p><strong>You should see</strong>: AI lists available skills, then loads the skill you selected</p><h3 id="step-3-trigger-context-compaction" tabindex="-1">Step 3: Trigger Context Compaction <a class="header-anchor" href="#step-3-trigger-context-compaction" aria-label="Permalink to &quot;Step 3: Trigger Context Compaction&quot;">​</a></h3><p><strong>Why</strong> Simulate a long session scenario to trigger OpenCode&#39;s compaction mechanism</p><p>Continuously send messages to simulate a long conversation:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Message 1: Test content</span></span>
<span class="line"><span>Message 2: Continue testing</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(Repeat 20-30 messages)</span></span></code></pre></div><p><strong>You should see</strong>:</p><ul><li>As messages increase, session history grows longer</li><li>After reaching a certain length, OpenCode automatically performs compaction</li><li>After compaction, early messages (including skill injection) are removed</li></ul><h3 id="step-4-check-restoration-effect" tabindex="-1">Step 4: Check Restoration Effect <a class="header-anchor" href="#step-4-check-restoration-effect" aria-label="Permalink to &quot;Step 4: Check Restoration Effect&quot;">​</a></h3><p><strong>Why</strong> Verify that the skill list is re-injected after compaction</p><p>After compaction, ask the AI to use a skill again:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Help me use the git-helper skill to create a new branch (assuming you have the git-helper skill installed)</span></span></code></pre></div><p><strong>You should see</strong>:</p><ul><li>AI still knows which skills are available (proving the skill list has been restored)</li><li>AI can normally load and use skills (proving skill functionality is unaffected by compaction)</li></ul><h3 id="step-5-verify-synthetic-message-injection" tabindex="-1">Step 5: Verify Synthetic Message Injection <a class="header-anchor" href="#step-5-verify-synthetic-message-injection" aria-label="Permalink to &quot;Step 5: Verify Synthetic Message Injection&quot;">​</a></h3><p><strong>Why</strong> Confirm that the restoration mechanism uses synthetic messages and does not interfere with the conversation</p><p>If the plugin supports it, check the session message history (depending on OpenCode functionality):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Use debugging tools to view session message history</span></span></code></pre></div><p><strong>You should see</strong>:</p><ul><li>The restored skill list messages are marked as <code>synthetic: true</code></li><li>These messages do not appear in the normal conversation interface</li></ul><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><p>After completing the above steps, you should be able to confirm:</p><ul><li>[ ] AI can still access the skill list in long sessions</li><li>[ ] Skill loading functionality works normally after compaction</li><li>[ ] The restoration process is completely transparent to users</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><h3 id="problem-1-ai-says-skill-not-found-after-compaction" tabindex="-1">Problem 1: AI says &quot;skill not found&quot; after compaction <a class="header-anchor" href="#problem-1-ai-says-skill-not-found-after-compaction" aria-label="Permalink to &quot;Problem 1: AI says &quot;skill not found&quot; after compaction&quot;">​</a></h3><p><strong>Possible causes</strong>:</p><ul><li>Plugin is not correctly listening to the <code>session.compacted</code> event</li><li>Skill directory path has changed</li></ul><p><strong>Solutions</strong>:</p><ol><li><p><strong>Verify that compaction event is triggered</strong></p><ul><li>Follow steps 3 and 4 in &quot;Follow Along&quot; to confirm that AI can still access the skill list after compaction</li><li>If AI can use skills normally, it means the compaction restoration mechanism is working</li></ul></li><li><p><strong>Check that the plugin is correctly loaded</strong></p><ul><li>Restart OpenCode</li><li>After starting a new session, ask the AI to list available skills (<code>get_available_skills</code>)</li><li>If you can see the skill list, the plugin is correctly loaded</li></ul></li></ol><h3 id="problem-2-restored-skill-list-is-empty" tabindex="-1">Problem 2: Restored skill list is empty <a class="header-anchor" href="#problem-2-restored-skill-list-is-empty" aria-label="Permalink to &quot;Problem 2: Restored skill list is empty&quot;">​</a></h3><p><strong>Possible causes</strong>:</p><ul><li>No skills in the skill discovery path</li><li>Incorrect skill file format</li></ul><p><strong>Solutions</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Manually query available skills</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Use</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get_available_skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> to</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> view</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skill</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span></code></pre></div><p>If an empty list is returned, check the skill directory and file format.</p><h3 id="problem-3-loaded-skill-state-is-lost-after-compaction" tabindex="-1">Problem 3: Loaded skill state is lost after compaction <a class="header-anchor" href="#problem-3-loaded-skill-state-is-lost-after-compaction" aria-label="Permalink to &quot;Problem 3: Loaded skill state is lost after compaction&quot;">​</a></h3><p><strong>This is expected behavior</strong>, not a bug. The restoration mechanism clears the <code>loadedSkillsPerSession</code> record, allowing the AI to re-evaluate which skills it needs.</p><p><strong>Solution</strong>: The AI will automatically decide whether to reload skills based on context—no manual intervention needed.</p><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The compaction restoration mechanism ensures skill availability in long sessions through:</p><ol><li><strong>Listening for compaction events</strong>: Automatically detects <code>session.compacted</code> events</li><li><strong>Re-injecting the skill list</strong>: Uses the <code>&lt;available-skills&gt;</code> tag to inject all skills</li><li><strong>Optional Superpowers restoration</strong>: If enabled, restores Superpowers prompts simultaneously</li><li><strong>Using synthetic messages</strong>: The restoration process is transparent to users and does not affect the conversation</li><li><strong>Resetting loaded records</strong>: Clears the loaded skills collection to allow re-evaluation</li></ol><p>This mechanism ensures:</p><ul><li>Skills remain available throughout long sessions</li><li>The restoration process is automated and seamless</li><li>The AI can decide which skills to use based on the latest context</li></ul><h2 id="preview-next-lesson" tabindex="-1">Preview: Next Lesson <a class="header-anchor" href="#preview-next-lesson" aria-label="Permalink to &quot;Preview: Next Lesson&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../../faq/troubleshooting/">Troubleshooting</a></strong>.</p><p>You will learn:</p><ul><li>Common error and exception handling methods</li><li>Troubleshooting techniques related to compaction restoration</li><li>Solutions to other usage issues</li></ul></blockquote><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line</th></tr></thead><tbody><tr><td>Compaction event listener</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L157" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-157</td></tr><tr><td>First message initialization</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L70-L105" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>70-105</td></tr><tr><td>Skill list injection</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L345-L370" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>345-370</td></tr><tr><td>Synthetic message injection</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>Session state management</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L25-L35" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>25-35</td></tr></tbody></table><p><strong>Key variables</strong>:</p><ul><li><code>setupCompleteSessions: Set&lt;string&gt;</code>: Records session IDs that have completed initialization</li><li><code>loadedSkillsPerSession: Map&lt;string, Set&lt;string&gt;&gt;</code>: Records the names of loaded skills for each session</li></ul><p><strong>Key functions</strong>:</p><ul><li><code>injectSkillsList()</code>: Injects the available skills list into the session</li><li><code>injectSyntheticContent()</code>: Uses synthetic messages to inject content</li><li><code>getSessionContext()</code>: Gets the session&#39;s model and agent information</li></ul></details>`,85)])])}const g=t(o,[["render",n]]);export{u as __pageData,g as default};
